from typing import List

class Solution:
    def minimumIndex(self, nums: List[int]) -> int:
        # Step 1: Find the dominant element
        freq = {}
        for num in nums:
            freq[num] = freq.get(num, 0) + 1

        # Find the dominant element
        dominant = None
        for num, count in freq.items():
            if count * 2 > len(nums):
                dominant = num
                break

        # Step 2: Compute prefix and suffix counts of the dominant element
        n = len(nums)
        prefix = [0] * n
        suffix = [0] * n

        prefix[0] = 1 if nums[0] == dominant else 0
        for i in range(1, n):
            prefix[i] = prefix[i - 1] + (1 if nums[i] == dominant else 0)

        suffix[-1] = 1 if nums[-1] == dominant else 0
        for i in range(n - 2, -1, -1):
            suffix[i] = suffix[i + 1] + (1 if nums[i] == dominant else 0)

        # Step 3: Check for valid splits
        for i in range(n - 1):
            left_count = prefix[i]
            right_count = suffix[i + 1]
            if left_count * 2 > (i + 1) and right_count * 2 > (n - i - 1):
                return i

        return -1
